mapper.select:

where c.category_id = #{categoryId}
  and c.del_flag = '0'
limit 1


where c.category_code = #{categoryCode}
  and c.del_flag = '0'
limit 1

select count(1)
from product_category
where parent_id = #{parentId}
  and category_name = #{categoryName}
  and del_flag = '0'

    and category_id <> #{excludeCategoryId}

select count(1)
from product_category_attribute
where category_id = #{categoryId}

mapper.insert:
insert into product_category(
    parent_id, ancestors, category_code, category_name, category_level,
    publish_enabled, sort_order, schema_version, status, del_flag,
    create_by, create_time, remark
) values (
    #{parentId}, #{ancestors}, #{categoryCode}, #{categoryName}, #{categoryLevel},
    #{publishEnabled}, #{sortOrder}, #{schemaVersion}, #{status}, '0',
    #{createBy}, sysdate(), #{remark}
)

mapper.select:
select *
from product_attribute
where del_flag = '0'

    and (attribute_code like concat('%', #{keyword}, '%') or attribute_name like concat('%', #{keyword}, '%'))


    and attribute_code like concat('%', #{attributeCode}, '%')


    and attribute_name like concat('%', #{attributeName}, '%')


    and attribute_type = #{attributeType}


    and option_source = #{optionSource}


    and status = #{status}

order by create_time desc, attribute_id desc

mapper.insert:
insert into product_attribute(
    attribute_code, attribute_name, attribute_type, option_source, dict_type,
    unit, value_precision, status, del_flag, create_by, create_time, remark
) values (
    #{attributeCode}, #{attributeName}, #{attributeType}, #{optionSource}, #{dictType},
    #{unit}, #{valuePrecision}, #{status}, '0', #{createBy}, sysdate(), #{remark}
)

mapper.select:
select count(1)
from product_category_attribute
where attribute_id = #{attributeId}

select count(1)
from product_attribute_option
where attribute_id = #{attributeId}
  and option_code = #{optionCode}

    and option_id <> #{excludeOptionId}

mapper.insert:
insert into product_attribute_option(
    attribute_id, option_code, option_label, sort_order, default_flag,
    status, create_by, create_time, remark
) values (
    #{attributeId}, #{optionCode}, #{optionLabel}, #{sortOrder}, #{defaultFlag},
    #{status}, #{createBy}, sysdate(), #{remark}
)

mapper.select:

where ca.category_id = #{categoryId}
  and ca.attribute_id = #{attributeId}
limit 1

mapper.insert:
insert into product_category_attribute(
    category_id, attribute_id, rule_mode, required_flag, visible_flag,
    editable_flag, filterable_flag, group_code, sort_order, placeholder,
    help_text, validation_rule, status, create_by, create_time, remark
) values (
    #{categoryId}, #{attributeId}, #{ruleMode}, #{requiredFlag}, #{visibleFlag},
    #{editableFlag}, #{filterableFlag}, #{groupCode}, #{sortOrder}, #{placeholder},
    #{helpText}, #{validationRule}, #{status}, #{createBy}, sysdate(), #{remark}
)
